  "inlineSchema": "// This is the Prisma schema for the POS system.\n// It defines all the tables and their relationships.\n\ngenerator client {\n  provider      = \"prisma-client-js\"\n  binaryTargets = [\"native\", \"darwin-arm64\"]\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// Users who can log into the system - admins, managers, and cashiers\nmodel User {\n  id        Int      @id @default(autoincrement())\n  username  String   @unique\n  password  String\n  fullName  String\n  role      Role     @default(CASHIER)\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  sales Sale[]\n\n  @@map(\"users\")\n}\n\nenum Role {\n  ADMIN\n  MANAGER\n  CASHIER\n}\n\n// Every product that can be sold in the store\nmodel Product {\n  id          Int      @id @default(autoincrement())\n  name        String\n  category    String\n  price       Float\n  barcode     String?  @unique\n  description String?\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  inventory Inventory?\n  saleItems SaleItem[]\n\n  @@map(\"products\")\n}\n\n// Tracks how much stock we have for each product\nmodel Inventory {\n  id            Int      @id @default(autoincrement())\n  productId     Int      @unique\n  quantity      Int      @default(0)\n  lowStockAlert Int      @default(10)\n  supplier      String?\n  updatedAt     DateTime @updatedAt\n\n  product Product @relation(fields: [productId], references: [id])\n\n  @@map(\"inventory\")\n}\n\n// Customers who shop at the store\nmodel Customer {\n  id            Int      @id @default(autoincrement())\n  name          String\n  phone         String?  @unique\n  email         String?  @unique\n  address       String?\n  loyaltyPoints Int      @default(0)\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  sales Sale[]\n\n  @@map(\"customers\")\n}\n\n// A single sale transaction\nmodel Sale {\n  id          Int        @id @default(autoincrement())\n  userId      Int\n  customerId  Int?\n  totalAmount Float\n  discount    Float      @default(0)\n  tax         Float      @default(0)\n  grandTotal  Float\n  status      SaleStatus @default(COMPLETED)\n  createdAt   DateTime   @default(now())\n\n  user      User       @relation(fields: [userId], references: [id])\n  customer  Customer?  @relation(fields: [customerId], references: [id])\n  saleItems SaleItem[]\n  payment   Payment?\n\n  @@map(\"sales\")\n}\n\nenum SaleStatus {\n  PENDING\n  COMPLETED\n  CANCELLED\n  REFUNDED\n}\n\n// Each line item inside a sale\nmodel SaleItem {\n  id        Int   @id @default(autoincrement())\n  saleId    Int\n  productId Int\n  quantity  Int\n  unitPrice Float\n  subtotal  Float\n\n  sale    Sale    @relation(fields: [saleId], references: [id])\n  product Product @relation(fields: [productId], references: [id])\n\n  @@map(\"sale_items\")\n}\n\n// Payment record for each completed sale\nmodel Payment {\n  id         Int           @id @default(autoincrement())\n  saleId     Int           @unique\n  method     PaymentMethod\n  amountPaid Float\n  change     Float         @default(0)\n  reference  String?\n  createdAt  DateTime      @default(now())\n\n  sale Sale @relation(fields: [saleId], references: [id])\n\n  @@map(\"payments\")\n}\n\nenum PaymentMethod {\n  CASH\n  MOBILE_MONEY\n  CARD\n}\n",
